#include <stdio.h>
#include <stdlib.h>

// Define the structure for a graph edge
typedef struct Edge {
    int src, dest;
} Edge;

// Define the structure for a graph
typedef struct Graph {
    int V, E;
    Edge* edge;
} Graph;

// Function to create a graph
Graph* createGraph(int vertices, int edges) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->V = vertices;
    graph->E = edges;
    graph->edge = (Edge*) malloc(edges * sizeof(Edge));
    return graph;
}

// Function to find bridges in a graph
void findBridges(Graph* graph) {
    int* tin = (int*) malloc(graph->V * sizeof(int));
    int* low = (int*) malloc(graph->V * sizeof(int));
    int* vis = (int*) malloc(graph->V * sizeof(int));
    int time = 0;

    // Initialize the arrays
    for (int i = 0; i < graph->V; i++) {
        tin[i] = -1;
        low[i] = -1;
        vis[i] = 0;
    }

    // Perform DFS to find bridges
    for (int i = 0; i < graph->V; i++) {
        if (vis[i] == 0) {
            dfs(graph, i, -1, &time, tin, low, vis);
        }
    }
}

// Function to perform DFS
void dfs(Graph* graph, int u, int parent, int* time, int* tin, int* low, int* vis) {
    vis[u] = 1;
    tin[u] = *time;
    low[u] = *time;
    (*time)++;

    for (int i = 0; i < graph->E; i++) {
        int v = (graph->edge[i].src == u) ? graph->edge[i].dest : graph->edge[i].src;
        if (v == parent) continue;
        if (vis[v] == 0) {
            dfs(graph, v, u, time, tin, low, vis);
            low[u] = min(low[u], low[v]);
            if (low[v] > tin[u]) {
                printf("Bridge: %d - %d\n", u, v);
            }
        } else if (tin[v] < tin[u]) {
            low[u] = min(low[u], tin[v]);
        }
    }
}

// Function to find the minimum of two numbers
int min(int a, int b) {
    return (a < b) ? a : b;
}

int main() {
    int vertices = 5;
    int edges = 6;
    Graph* graph = createGraph(vertices, edges);
    graph->edge[0].src = 0;
    graph->edge[0].dest = 1;
    graph->edge[1].src = 1;
    graph->edge[1].dest = 2;
    graph->edge[2].src = 2;
    graph->edge[2].dest = 0;
    graph->edge[3].src = 1;
    graph->edge[3].dest = 3;
    graph->edge[4].src = 3;
    graph->edge[4].dest = 4;
    graph->edge[5].src = 4;
    graph->edge[5].dest = 3;
    findBridges(graph);
    return 0;
}

